mapper.select:
SELECT ROW_NUMBER() OVER(ORDER BY reg_date DESC) row_num
	, id, title, start_date, end_date, reg_date, mod_date, is_published
FROM project
WHERE
	admin_id = #{adminId}
	AND is_deleted = #{isDeleted}

mapper.insert:
INSERT INTO project
	(admin_id, title, summary, team_size, key_features, tech_stack
	,start_date, end_date, github_url, demo_url, ppt_url, is_published) 
VALUES
	(#{adminId}, #{title}, #{summary}, #{teamSize}, #{keyFeatures}, #{techStack}
	,#{startDate}, #{endDate}, #{githubUrl}, #{demoUrl}, #{pptUrl}, #{is_published});

mapper.update:
UPDATE project
SET
	title = #{title}
	,summary = #{summary}
	,team_size = #{teamSize}
	,key_features = #{keyFeatures}
	,tech_stack = #{techStack}
	,start_date = #{startDate}
	,end_date = #{endDate}
	,github_url = #{githubUrl}
	,demo_url = #{demoUrl}
	,ppt_url = #{pptUrl}
	,is_published = #{isPublished}
WHERE
	id = #{id}
	AND admin_id = #{adminId}

UPDATE project_note
SET title = #{title}, url = #{url}
WHERE project_id = #{projectId}

UPDATE section
SET title = #{title}, content = #{content}
WHERE project_id = #{projectId} AND about_id = #{aboutId}

UPDATE image
SET ori_name = #{oriName}, saved_name = #{savedName}, extension = #{extension}
WHERE project_id = #{projectId} AND about_id = #{aboutId}
